const checkpoints = [];

// Load data
const searchParams = JSON.parse(localStorage.getItem('task1_tourSearchParams') || 'null');
const tours = JSON.parse(localStorage.getItem('tours') || '[]');
const tourDepartures = JSON.parse(localStorage.getItem('tour_departures') || '[]');
const tourBookings = JSON.parse(localStorage.getItem('tour_bookings') || '[]');
const cartItems = JSON.parse(localStorage.getItem('booking_cart_items') || '[]');

// CP1 (0.40): User searched tours with correct filters for the task
let cp1Passed = false;
if (searchParams) {
  const destOk = searchParams.destinationCountry === 'Japan';
  const start = searchParams.startDate ? new Date(searchParams.startDate) : null;
  const end = searchParams.endDate ? new Date(searchParams.endDate) : null;
  const datesOk = !!start && !!end && start.getFullYear() === 2025 && start.getMonth() === 3 && end.getFullYear() === 2025 && end.getMonth() === 3; // April = month 3
  const durOk = searchParams.minDurationDays === 7 && searchParams.maxDurationDays === 7;
  const priceOk = typeof searchParams.maxPricePerPerson === 'number' && searchParams.maxPricePerPerson <= 2000;
  const accLevels = Array.isArray(searchParams.accommodationLevels) ? searchParams.accommodationLevels : [];
  const accOk = accLevels.includes('standard_3_star');
  cp1Passed = destOk && datesOk && durOk && priceOk && accOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// Identify qualifying tour bookings based on task criteria
const qualifyingTourBookings = tourBookings.filter(tb => {
  const tour = tours.find(t => t.id === tb.tourId);
  const departure = tourDepartures.find(d => d.id === tb.tourDepartureId);
  if (!tour || !departure) return false;

  const startDate = tb.startDate || (departure.departureDate || null);
  if (!startDate) return false;
  const start = new Date(startDate);
  const startYear = start.getFullYear();
  const startMonth = start.getMonth();
  const duration = typeof departure.durationDays === 'number' ? departure.durationDays : tour.durationDays;

  const dateOk = startYear === 2025 && startMonth === 3; // April 2025
  const destOk = tour.destinationCountry === 'Japan';
  const durOk = duration === 7;
  const adultsOk = tb.adults === 2;
  const childrenOk = (tb.children || 0) === 0;
  const accOk = tb.accommodationLevel === 'standard_3_star';
  const priceOk = typeof tb.pricePerPerson === 'number' && tb.pricePerPerson <= 2000;
  const guidedOk = tour.isGuided === undefined ? true : !!tour.isGuided;

  return dateOk && destOk && durOk && adultsOk && childrenOk && accOk && priceOk && guidedOk;
});

// CP2 (0.30): User created at least one qualifying guided Japan 7-day tour booking for 2 adults in April 2025 under $2,000 with 3-star accommodation
const cp2Passed = qualifyingTourBookings.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.30): At least one qualifying tour booking was added to the cart
let cp3Passed = false;
if (qualifyingTourBookings.length > 0) {
  const qualifyingIds = new Set(qualifyingTourBookings.map(tb => tb.id));
  cp3Passed = cartItems.some(ci => ci.itemType === 'tour_booking' && qualifyingIds.has(ci.itemRefId));
}
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

// Final score
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('blog_articles') || '[]');
const savedArticles = JSON.parse(localStorage.getItem('saved_articles') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const readingListArticles = JSON.parse(localStorage.getItem('reading_list_articles') || '[]');

// Determine which articles are Paris museum-related (destinationCity Paris + any 'museum' tag)
const parisMuseumArticleIds = articles.filter(a => {
  const cityOk = (a.destinationCity || '').toLowerCase() === 'paris';
  const tags = Array.isArray(a.tags) ? a.tags.map(t => String(t).toLowerCase()) : [];
  const hasMuseumTag = tags.some(t => t.includes('museum'));
  return cityOk && hasMuseumTag;
}).map(a => a.id);

// CP1 (0.35): User saved at least 3 Paris museum-related articles
const qualifyingSaved = savedArticles.filter(sa => parisMuseumArticleIds.includes(sa.articleId));
const cp1Passed = qualifyingSaved.length >= 3;
checkpoints.push({ passed: cp1Passed, weight: 0.35 });

// Find a reading list whose name includes 'paris weekend' (case-insensitive)
const parisWeekendList = readingLists.find(rl => (rl.name || '').toLowerCase().includes('paris weekend')) || null;

// CP2 (0.30): 'Paris Weekend' reading list exists
const cp2Passed = !!parisWeekendList;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.35): 'Paris Weekend' list contains at least 3 Paris museum-related articles
let cp3Passed = false;
if (parisWeekendList) {
  const listArticles = readingListArticles.filter(rla => rla.readingListId === parisWeekendList.id);
  const qualifyingInList = listArticles.filter(rla => parisMuseumArticleIds.includes(rla.articleId));
  cp3Passed = qualifyingInList.length >= 3;
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task3_packageSearchParams') || 'null');
const compared = JSON.parse(localStorage.getItem('task3_comparedPackageIds') || 'null');
const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');

// CP1 (0.35): User searched with correct filters (Spain, beach, July 2025, 5–7 nights, rating ≥4.0)
let cp1Passed = false;
if (searchParams) {
  const destOk = searchParams.destinationCountry === 'Spain';
  const themeOk = searchParams.theme === 'beach';
  const travelMonthOk = searchParams.travelMonth === '2025-07';
  const minDurOk = searchParams.minDurationNights === 5;
  const maxDurOk = searchParams.maxDurationNights === 7;
  const minRatingOk = typeof searchParams.minRating === 'number' && searchParams.minRating >= 4.0;
  cp1Passed = destOk && themeOk && travelMonthOk && minDurOk && maxDurOk && minRatingOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.35 });

// Qualifying packages according to task criteria
const qualifyingPkgs = packages.filter(p => {
  if (p.destinationCountry !== 'Spain') return false;
  if (p.theme !== 'beach') return false;
  if (!p.startDate) return false;
  const d = new Date(p.startDate);
  if (isNaN(d.getTime())) return false;
  const ym = d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0');
  if (ym !== '2025-07') return false;
  if (typeof p.durationNights === 'number' && (p.durationNights < 5 || p.durationNights > 7)) return false;
  if (typeof p.rating === 'number' && p.rating < 4.0) return false;
  return true;
});

// CP2 (0.30): User compared at least two qualifying Spain beach packages (July 2025, 5–7 nights, rating ≥4.0)
let firstTwoComparedQualifying = [];
let cp2Passed = false;
if (compared && Array.isArray(compared.packageIds)) {
  const firstTwo = compared.packageIds.slice(0, 2);
  firstTwoComparedQualifying = firstTwo
    .map(id => packages.find(p => p.id === id))
    .filter(p => p && qualifyingPkgs.some(q => q.id === p.id));
  cp2Passed = firstTwoComparedQualifying.length >= 2;
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.35): User added to wishlist the better of the two compared packages (higher rating, then lower price)
let cp3Passed = false;
if (firstTwoComparedQualifying.length >= 2) {
  const p1 = firstTwoComparedQualifying[0];
  const p2 = firstTwoComparedQualifying[1];
  let winner = p1;
  if ((p2.rating || 0) > (p1.rating || 0)) {
    winner = p2;
  } else if ((p2.rating || 0) === (p1.rating || 0) && (p2.pricePerPerson || 0) < (p1.pricePerPerson || 0)) {
    winner = p2;
  }
  cp3Passed = wishlistItems.some(wi => wi.itemType === 'package' && wi.itemRefId === winner.id);
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task4_bundleSearchParams') || 'null');
const bundles = JSON.parse(localStorage.getItem('bundles') || '[]');
const bundleBookings = JSON.parse(localStorage.getItem('bundle_bookings') || '[]');
const cartItems = JSON.parse(localStorage.getItem('booking_cart_items') || '[]');

// CP1 (0.40): User searched bundles with correct filters (LAX→JFK, Sept 10–13 2025, 1 adult, non-stop, max $1,200, sort by lowest total price)
let cp1Passed = false;
if (searchParams) {
  const originOk = searchParams.originAirportCode === 'LAX';
  const destOk = searchParams.destinationAirportCode === 'JFK';
  const depOk = searchParams.departureDate === '2025-09-10';
  const retOk = searchParams.returnDate === '2025-09-13';
  const adultsOk = searchParams.adults === 1;
  const nonStopOk = searchParams.nonStopOnly === true;
  const maxPriceOk = typeof searchParams.maxTotalPrice === 'number' && searchParams.maxTotalPrice <= 1200;
  const sortOk = searchParams.sortBy === 'total_price_low_to_high';
  cp1Passed = originOk && destOk && depOk && retOk && adultsOk && nonStopOk && maxPriceOk && sortOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// Determine all qualifying bundles (criteria from task, not yet enforcing 'cheapest')
const qualifyingBundles = bundles.filter(b => {
  if (b.originAirportCode !== 'LAX') return false;
  if (b.destinationAirportCode !== 'JFK') return false;
  const depDate = b.departureDateTime ? String(b.departureDateTime).substring(0, 10) : null;
  const retDate = b.returnDateTime ? String(b.returnDateTime).substring(0, 10) : null;
  if (depDate !== '2025-09-10') return false;
  if (retDate !== '2025-09-13') return false;
  if (!b.isNonStopFlight) return false;
  if (typeof b.totalPrice === 'number' && b.totalPrice > 1200) return false;
  if (b.nights !== 3) return false;
  return true;
});

// CP2 (0.30): User created a booking for at least one qualifying non-stop LAX–JFK 3-night bundle under $1,200 and added it to the cart
let qualifyingBookingsForCriteria = [];
let cp2Passed = false;
if (qualifyingBundles.length > 0) {
  const qualifyingIds = new Set(qualifyingBundles.map(b => b.id));
  qualifyingBookingsForCriteria = bundleBookings.filter(bb => {
    if (!qualifyingIds.has(bb.bundleId)) return false;
    if (bb.adults !== 1) return false;
    return true;
  });
  if (qualifyingBookingsForCriteria.length > 0) {
    const bookingIdSet = new Set(qualifyingBookingsForCriteria.map(bb => bb.id));
    const inCart = cartItems.some(ci => ci.itemType === 'bundle_booking' && bookingIdSet.has(ci.itemRefId));
    cp2Passed = inCart;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.30): Among qualifying bundles, user booked the cheapest one
let cp3Passed = false;
if (qualifyingBundles.length > 0 && qualifyingBookingsForCriteria.length > 0) {
  const cheapestBundle = qualifyingBundles.slice().sort((a, b) => (a.totalPrice || 0) - (b.totalPrice || 0))[0];
  const bookedCheapest = qualifyingBookingsForCriteria.some(bb => bb.bundleId === cheapestBundle.id);
  cp3Passed = bookedCheapest;
}
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

// Find subscription for the target email (case-insensitive)
const targetEmail = 'test@example.com';
const subscription = subs.find(s => (s.email || '').toLowerCase() === targetEmail.toLowerCase()) || null;

// CP1 (0.60): Subscription exists for test@example.com with weekly frequency and includes 'budget_travel' topic
let cp1Passed = false;
if (subscription) {
  const freqOk = subscription.frequency === 'weekly';
  const topics = Array.isArray(subscription.topics) ? subscription.topics : [];
  const hasBudget = topics.includes('budget_travel');
  cp1Passed = freqOk && hasBudget;
}
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.40): Subscription has correct name and opted-in promotions flag
let cp2Passed = false;
if (subscription) {
  const nameOk = (subscription.name || '') === 'Alex Traveler';
  const promosOk = subscription.agreedToPromotions === true;
  cp2Passed = nameOk && promosOk;
}
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task6_hotelSearchParams') || 'null');
const hotels = JSON.parse(localStorage.getItem('hotels') || '[]');
const roomTypes = JSON.parse(localStorage.getItem('hotel_room_types') || '[]');
const hotelBookings = JSON.parse(localStorage.getItem('hotel_bookings') || '[]');
const cartItems = JSON.parse(localStorage.getItem('booking_cart_items') || '[]');

// CP1 (0.40): User searched with correct hotel filters for Rome family stay in Aug 2025
let cp1Passed = false;
if (searchParams) {
  const cityOk = (searchParams.city || '').toLowerCase() === 'rome';
  const countryOk = (searchParams.country || '').toLowerCase() === 'italy';
  const checkInOk = searchParams.checkInDate && String(searchParams.checkInDate).startsWith('2025-08-01');
  const checkOutOk = searchParams.checkOutDate && String(searchParams.checkOutDate).startsWith('2025-08-05');
  const adultsOk = searchParams.adults === 2;
  const childrenOk = searchParams.children === 2;
  const maxPriceOk = typeof searchParams.maxPricePerNight === 'number' && searchParams.maxPricePerNight <= 250;
  const minRatingOk = typeof searchParams.minGuestRating === 'number' && searchParams.minGuestRating >= 4.5;
  const amenities = Array.isArray(searchParams.amenities) ? searchParams.amenities : [];
  const hasBreakfast = amenities.includes('free_breakfast');
  const hasWifi = amenities.includes('free_wifi');
  const familyOnlyOk = searchParams.familyFriendlyOnly === true;
  cp1Passed = cityOk && countryOk && checkInOk && checkOutOk && adultsOk && childrenOk && maxPriceOk && minRatingOk && hasBreakfast && hasWifi && familyOnlyOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// Qualifying hotel bookings according to task criteria
const qualifyingBookings = hotelBookings.filter(hb => {
  const hotel = hotels.find(h => h.id === hb.hotelId);
  const room = roomTypes.find(r => r.id === hb.roomTypeId);
  if (!hotel || !room) return false;

  const cityOk = (hotel.city || '').toLowerCase() === 'rome';
  const countryOk = (hotel.country || '').toLowerCase() === 'italy';
  const familyOk = !!hotel.isFamilyFriendly;
  const ratingOk = typeof hotel.guestRating === 'number' && hotel.guestRating >= 4.5;
  const hotelAmenities = Array.isArray(hotel.amenities) ? hotel.amenities : [];
  const hasBreakfast = hotelAmenities.includes('free_breakfast');
  const hasWifi = hotelAmenities.includes('free_wifi');

  const nightsOk = hb.nights === 4;
  const start = hb.checkInDate ? new Date(hb.checkInDate) : null;
  const end = hb.checkOutDate ? new Date(hb.checkOutDate) : null;
  const datesOk = !!start && !!end && start.getFullYear() === 2025 && start.getMonth() === 7 && end.getFullYear() === 2025 && end.getMonth() === 7; // August

  const guestsOk = hb.adults === 2 && (hb.children || 0) === 2;
  const priceOk = typeof hb.pricePerNight === 'number' && hb.pricePerNight <= 250 && (hb.currency || '').toLowerCase() === 'usd';
  const freeCancelOk = !!room.freeCancellation;

  return cityOk && countryOk && familyOk && ratingOk && hasBreakfast && hasWifi && nightsOk && datesOk && guestsOk && priceOk && freeCancelOk;
});

// CP2 (0.30): User created at least one qualifying Rome family hotel booking matching all criteria
const cp2Passed = qualifyingBookings.length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.30): At least one qualifying hotel booking was added to the cart
let cp3Passed = false;
if (qualifyingBookings.length > 0) {
  const bookingIdSet = new Set(qualifyingBookings.map(hb => hb.id));
  cp3Passed = cartItems.some(ci => ci.itemType === 'hotel_booking' && bookingIdSet.has(ci.itemRefId));
}
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
const policyConfigs = JSON.parse(localStorage.getItem('insurance_policy_configs') || '[]');

// Helper: determine if a policy config matches the task criteria
function isQualifyingPolicyConfig(pc) {
  const plan = plans.find(p => p.id === pc.planId);
  if (!plan) return false;
  const midTierOk = plan.tier === 'standard';
  const costOk = pc.tripCost === 3000;
  const durationOk = pc.tripDurationDays === 14;

  const startStr = pc.coverageStartDate || '';
  const endStr = pc.coverageEndDate || '';
  const startOk = startStr.startsWith('2025-06');
  const endOk = endStr.startsWith('2025-06');

  const addons = Array.isArray(pc.addons) ? pc.addons : [];
  const hasTripCancel = addons.includes('trip_cancellation_protection');

  return midTierOk && costOk && durationOk && startOk && endOk && hasTripCancel;
}

const qualifyingConfigs = policyConfigs.filter(isQualifyingPolicyConfig);

// CP1 (0.50): At least one policy config exists matching mid-tier standard plan, $3,000 cost, 14 days in June 2025 with trip cancellation protection
const cp1Passed = qualifyingConfigs.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.50): Qualifying policy config has a computed premium in USD (indicating policy review was reached)
let cp2Passed = false;
if (qualifyingConfigs.length > 0) {
  cp2Passed = qualifyingConfigs.some(pc => typeof pc.estimatedPremium === 'number' && pc.estimatedPremium > 0 && (!pc.currency || pc.currency.toLowerCase() === 'usd'));
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const itineraries = JSON.parse(localStorage.getItem('custom_itineraries') || '[]');
const itCities = JSON.parse(localStorage.getItem('custom_itinerary_cities') || '[]');
const itActivities = JSON.parse(localStorage.getItem('custom_itinerary_activities') || '[]');
const activityTemplates = JSON.parse(localStorage.getItem('activity_templates') || '[]');

// Find itineraries matching country=Italy, totalNights=6, start in May 2025, 3-star hotels, and name like 'Italy May 2025'
const qualifyingItineraries = itineraries.filter(it => {
  const countryOk = (it.country || '').toLowerCase() === 'italy';
  const nightsOk = it.totalNights === 6;
  const startStr = it.startDate || '';
  const startOk = startStr.startsWith('2025-05');
  const accOk = it.accommodationPreferenceLevel === 'three_star_hotels';
  const nameLower = (it.name || '').toLowerCase();
  const nameOk = nameLower.includes('italy') && nameLower.includes('may');
  return countryOk && nightsOk && startOk && accOk && nameOk;
});

// CP1 (0.40): At least one saved itinerary matches Italy, 6 nights, May 2025 start, 3-star level, and appropriate name
const cp1Passed = qualifyingItineraries.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// For city stays and activities we evaluate against the first qualifying itinerary (any one is fine)
let cp2Passed = false;
let cp3Passed = false;

if (qualifyingItineraries.length > 0) {
  const it = qualifyingItineraries[0];
  const citiesForIt = itCities.filter(c => c.itineraryId === it.id);

  // CP2 (0.30): Itinerary has 2 nights each in Rome, Florence, and Venice
  const rome = citiesForIt.find(c => (c.cityName || '').toLowerCase() === 'rome');
  const florence = citiesForIt.find(c => (c.cityName || '').toLowerCase() === 'florence');
  const venice = citiesForIt.find(c => (c.cityName || '').toLowerCase() === 'venice');
  const romeOk = rome && rome.nights === 2;
  const florenceOk = florence && florence.nights === 2;
  const veniceOk = venice && venice.nights === 2;
  cp2Passed = romeOk && florenceOk && veniceOk;
  checkpoints.push({ passed: cp2Passed, weight: 0.3 });

  // CP3 (0.30): At least one guided/walking tour in Rome and at least one activity in Venice
  const actsForIt = itActivities.filter(a => a.itineraryId === it.id);

  const romeActs = actsForIt.filter(a => (a.cityName || '').toLowerCase() === 'rome');
  const veniceActs = actsForIt.filter(a => (a.cityName || '').toLowerCase() === 'venice');

  const romeGuidedOrWalking = romeActs.some(a => {
    const tmpl = activityTemplates.find(t => t.id === a.activityTemplateId);
    if (!tmpl) return false;
    const type = tmpl.activityType;
    return type === 'guided_tour' || type === 'walking_tour';
  });

  const veniceHasAny = veniceActs.some(a => {
    const tmpl = activityTemplates.find(t => t.id === a.activityTemplateId);
    return !!tmpl; // any valid activity in Venice
  });

  cp3Passed = romeGuidedOrWalking && veniceHasAny;
  checkpoints.push({ passed: cp3Passed, weight: 0.3 });
} else {
  // If no qualifying itinerary, still push CP2 and CP3 as failed to keep weights summing to 1.0
  checkpoints.push({ passed: false, weight: 0.3 });
  checkpoints.push({ passed: false, weight: 0.3 });
}

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
